module top_module(input [7:0] DataIN,
						input clock, Reset_b,
						output [7:0] DataOUT);reg [7:0] Invalid_DataOUTreg;
	always @ (posedge clock) begin
		if(Reset_b == 0)
			Invalid_DataOUTreg <= 8'b00000000;
		else
			Invalid_DataOUTreg <= DataIN;
	end
	assign DataOUT = Invalid_DataOUTreg;endmodule
